(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"sample-variance",fields:[{"key":"values","label":"자료 입력","type":"textarea","placeholder":"예: 1, 2, 3, 4","default":"","options":[],"raw":true}],hint:"표본분산은 편차제곱합을 n-1로 나눕니다.",compute:function(x){var a=String(x.values||"").split(/[\s,;]+/).filter(Boolean).map(Number);if(a.length<2||a.some(function(v){return !Number.isFinite(v);})){return{error:"유효한 숫자 자료를 2개 이상 입력해 주세요."};}var n=a.length,mean=a.reduce(function(s,v){return s+v;},0)/n,ss=a.reduce(function(s,v){var d=v-mean;return s+d*d;},0),variance=ss/(n-1);return{count:n,mean:mean,variance:variance,stddev:Math.sqrt(variance)};},format:function(r,api){return api.resultCard("표본분산",api.formatNumber(r.variance,6),"")+api.resultCard("표본표준편차",api.formatNumber(r.stddev,6),"")+api.resultCard("평균·자료 수",api.formatNumber(r.mean,6),r.count+"개");}},{id:"quartile-iqr",fields:[{"key":"values","label":"자료 입력","type":"textarea","placeholder":"예: 1, 2, 3, 4, 5","default":"","options":[],"raw":true}],hint:"",compute:function(x){var a=String(x.values||"").split(/[\s,;]+/).filter(Boolean).map(Number);if(!a.length||a.some(function(v){return !Number.isFinite(v);})){return{error:"유효한 숫자 자료를 1개 이상 입력해 주세요."};}a.sort(function(p,q){return p-q;});function q(p){var pos=(a.length-1)*p,lo=Math.floor(pos),hi=Math.ceil(pos);return lo===hi?a[lo]:a[lo]+(a[hi]-a[lo])*(pos-lo);}var q1=q(.25),q2=q(.5),q3=q(.75);return{count:a.length,q1:q1,median:q2,q3:q3,iqr:q3-q1,min:a[0],max:a[a.length-1]};},format:function(r,api){return api.resultCard("Q1 · 중앙값 · Q3",api.formatNumber(r.q1,4)+" · "+api.formatNumber(r.median,4)+" · "+api.formatNumber(r.q3,4),"")+api.resultCard("사분위범위 IQR",api.formatNumber(r.iqr,4),"")+api.resultCard("최솟값 · 최댓값",api.formatNumber(r.min,4)+" · "+api.formatNumber(r.max,4),r.count+"개");}},{id:"percentile-rank-lte",fields:[{"key":"values","label":"자료 입력","type":"textarea","placeholder":"예: 10, 20, 30, 40","default":"","options":[],"raw":true},{"key":"target","label":"기준값","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"여기서는 기준값 이하 자료의 비율을 사용합니다.",compute:function(x){var a=String(x.values||"").split(/[\s,;]+/).filter(Boolean).map(Number),t=Number(x.target);if(!a.length||a.some(function(v){return !Number.isFinite(v);})||!Number.isFinite(t)){return{error:"유효한 자료와 기준값을 입력해 주세요."};}var below=a.filter(function(v){return v<t;}).length,equal=a.filter(function(v){return v===t;}).length,lte=below+equal;return{count:a.length,below:below,equal:equal,lte:lte,percentile:lte/a.length*100};},format:function(r,api){return api.resultCard("기준값 이하 비율",api.formatNumber(r.percentile,2)+"%","")+api.resultCard("이하 자료 수",r.lte+"개",r.count+"개 중")+api.resultCard("미만 · 동일",r.below+"개 · "+r.equal+"개","");}},{id:"coefficient-of-variation",fields:[{"key":"values","label":"자료 입력","type":"textarea","placeholder":"예: 10, 20, 30","default":"","options":[],"raw":true}],hint:"",compute:function(x){var a=String(x.values||"").split(/[\s,;]+/).filter(Boolean).map(Number);if(!a.length||a.some(function(v){return !Number.isFinite(v);})){return{error:"유효한 숫자 자료를 입력해 주세요."};}var n=a.length,mean=a.reduce(function(s,v){return s+v;},0)/n;if(mean===0)return{error:"평균이 0이면 변동계수를 계산할 수 없습니다."};var variance=a.reduce(function(s,v){var d=v-mean;return s+d*d;},0)/n,std=Math.sqrt(variance);return{count:n,mean:mean,stddev:std,cv:std/Math.abs(mean)*100};},format:function(r,api){return api.resultCard("변동계수 CV",api.formatNumber(r.cv,4)+"%","")+api.resultCard("평균",api.formatNumber(r.mean,6),"")+api.resultCard("모표준편차",api.formatNumber(r.stddev,6),r.count+"개 자료");}},{id:"weighted-mean-list",fields:[{"key":"values","label":"값 목록","type":"textarea","placeholder":"예: 10, 20, 30","default":"","options":[],"raw":true},{"key":"weights","label":"가중치 목록","type":"textarea","placeholder":"예: 1, 2, 1","default":"","options":[],"raw":true}],hint:"",compute:function(x){var v=String(x.values||"").split(/[\s,;]+/).filter(Boolean).map(Number),w=String(x.weights||"").split(/[\s,;]+/).filter(Boolean).map(Number);if(!v.length||v.length!==w.length||v.some(function(n){return !Number.isFinite(n);})||w.some(function(n){return !Number.isFinite(n)||n<0;})){return{error:"값과 가중치를 같은 개수로 입력하고 가중치는 0 이상으로 입력해 주세요."};}var sw=w.reduce(function(s,n){return s+n;},0);if(sw<=0)return{error:"가중치 합은 0보다 커야 합니다."};var weighted=v.reduce(function(s,n,i){return s+n*w[i];},0);return{count:v.length,totalWeight:sw,weightedSum:weighted,mean:weighted/sw};},format:function(r,api){return api.resultCard("가중평균",api.formatNumber(r.mean,6),"")+api.resultCard("가중합",api.formatNumber(r.weightedSum,6),"")+api.resultCard("가중치 합",api.formatNumber(r.totalWeight,6),r.count+"개 항목");}},{id:"linear-interpolation",fields:[{"key":"x1","label":"x₁","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"y1","label":"y₁","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"x2","label":"x₂","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"y2","label":"y₂","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"targetX","label":"구할 x","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var x1=Number(x.x1),y1=Number(x.y1),x2=Number(x.x2),y2=Number(x.y2),t=Number(x.targetX);if(![x1,y1,x2,y2,t].every(Number.isFinite)||x1===x2)return{error:"모든 값을 숫자로 입력하고 x₁과 x₂는 서로 다르게 입력해 주세요."};var ratio=(t-x1)/(x2-x1),y=y1+ratio*(y2-y1);return{ratio:ratio,targetY:y,deltaX:x2-x1,deltaY:y2-y1};},format:function(r,api){return api.resultCard("보간 y값",api.formatNumber(r.targetY,8),"")+api.resultCard("구간 비율",api.formatNumber(r.ratio,6),"")+api.resultCard("Δx · Δy",api.formatNumber(r.deltaX,6)+" · "+api.formatNumber(r.deltaY,6),"");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
